import { useEffect, useMemo, useState } from "react";
import { useNavigate } from "react-router-dom";
import api from "../../api/axios";
import { formatDisplayTime } from "./CustomerAppointmentForm";

const STATUS_META = {
  scheduled: { label: "Scheduled", badge: "badge badgeCyan" },
  completed: { label: "Completed", badge: "badge badgeGreen" },
  cancelled: { label: "Cancelled", badge: "badge badgePink" },
};

function MetricCard({ label, value, sub }) {
  return (
    <div className="kpiCard">
      <div className="kpiLabel">{label}</div>
      <div className="kpiValue">{value}</div>
      <div className="kpiSub">{sub}</div>
    </div>
  );
}

function DetailRow({ label, value }) {
  return (
    <div style={{ display: "flex", justifyContent: "space-between", gap: "12px", alignItems: "flex-start" }}>
      <div style={{ fontSize: "12px", textTransform: "uppercase", letterSpacing: "0.06em", color: "var(--text-muted)", minWidth: "84px" }}>
        {label}
      </div>
      <div style={{ textAlign: "right", color: "var(--text)", fontWeight: 600 }}>{value}</div>
    </div>
  );
}

export default function MyAppointments() {
  const [appointments, setAppointments] = useState([]);
  const [deleting, setDeleting] = useState(null);
  const navigate = useNavigate();

  useEffect(() => {
    api
      .get("/customer/appointments/my")
      .then((res) => setAppointments(res.data))
      .catch((err) => alert(err.response?.data?.message || "Failed to load"));
  }, []);

  const stats = useMemo(() => {
    const total = appointments.length;
    const scheduled = appointments.filter((appointment) => appointment.status === "scheduled").length;
    const completed = appointments.filter((appointment) => appointment.status === "completed").length;
    return { total, scheduled, completed };
  }, [appointments]);

  const deleteAppointment = async (id) => {
    if (!window.confirm("Are you sure you want to cancel this appointment?")) return;

    setDeleting(id);
    try {
      await api.delete(`/customer/appointments/${id}`);
      setAppointments((current) => current.filter((appointment) => appointment._id !== id));
    } catch (err) {
      const errorMsg = err.response?.data?.message || err.message || "Failed to cancel appointment";
      alert(errorMsg);
    } finally {
      setDeleting(null);
    }
  };

  return (
    <div className="page">
      <div className="pageHead">
        <div>
          <div className="pageTitle">My Appointments</div>
          <div className="pageSub">Track your showroom visits, assigned support staff, and upcoming sessions in a cleaner customer experience.</div>
        </div>
        <button onClick={() => navigate("/book-appointment")} className="btn btnPrimary">
          Book Appointment
        </button>
      </div>

      <div
        className="card cardPad"
        style={{
          display: "grid",
          gap: "16px",
          marginBottom: "20px",
          background: "linear-gradient(135deg, rgba(12,58,87,0.96) 0%, rgba(17,73,109,0.95) 62%, rgba(141,187,1,0.92) 100%)",
          color: "#fff",
        }}
      >
        <div style={{ fontSize: "12px", textTransform: "uppercase", letterSpacing: "0.14em", opacity: 0.72 }}>Customer Overview</div>
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(180px, 1fr))", gap: "14px" }}>
          <SummaryTile label="Total" value={stats.total} />
          <SummaryTile label="Scheduled" value={stats.scheduled} />
          <SummaryTile label="Completed" value={stats.completed} />
          <SummaryTile label="Next Step" value={stats.scheduled ? "Ready" : "Plan"} />
        </div>
      </div>

      {appointments.length === 0 ? (
        <div className="card cardPad" style={{ maxWidth: "760px", margin: "32px auto", textAlign: "center", color: "var(--text-muted)" }}>
          <div style={{ fontSize: "22px", fontWeight: 800, color: "var(--navy)", marginBottom: "10px" }}>No appointments yet</div>
          <div style={{ marginBottom: "18px", lineHeight: 1.7 }}>
            Book your first appointment to schedule a showroom visit or test drive.
          </div>
          <button onClick={() => navigate("/book-appointment")} className="btn btnPrimary">
            Book Your First Appointment
          </button>
        </div>
      ) : (
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(320px, 1fr))", gap: "18px" }}>
          {appointments.map((appointment) => {
            const status = STATUS_META[appointment.status] || STATUS_META.scheduled;

            return (
              <div key={appointment._id} className="card cardPad" style={{ display: "grid", gap: "16px" }}>
                <div style={{ display: "flex", justifyContent: "space-between", gap: "12px", alignItems: "flex-start" }}>
                  <div style={{ display: "grid", gap: "4px" }}>
                    <div style={{ fontSize: "22px", fontWeight: 800, color: "var(--navy)", lineHeight: 1.2 }}>
                      {appointment.vehicle?.brand} {appointment.vehicle?.model || appointment.vehicle?.type || ""}
                    </div>
                    <div className="sub">{appointment.vehicle?.year || "Vehicle"} • Premium visit</div>
                  </div>
                  <span className={status.badge}>{status.label}</span>
                </div>

                <div
                  style={{
                    display: "grid",
                    gap: "10px",
                    padding: "16px",
                    borderRadius: "16px",
                    background: "rgba(255,255,255,0.76)",
                    border: "1px solid var(--border)",
                  }}
                >
                  <DetailRow
                    label="Date"
                    value={new Date(appointment.date).toLocaleDateString("en-US", {
                      weekday: "short",
                      month: "short",
                      day: "numeric",
                      year: "numeric",
                    })}
                  />
                  <DetailRow label="Session" value={formatDisplayTime(appointment.time)} />
                  <DetailRow label="Staff" value={appointment.staffMember?.name || "To be assigned"} />
                  <DetailRow label="Email" value={appointment.staffMember?.email || "Shared after assignment"} />
                </div>

                <div style={{ display: "flex", gap: "10px", flexWrap: "wrap" }}>
                  <button
                    onClick={() => navigate(`/edit-my-appointment/${appointment._id}`)}
                    className="btn"
                    disabled={appointment.status !== "scheduled"}
                    style={{ flex: 1, opacity: appointment.status !== "scheduled" ? 0.5 : 1 }}
                  >
                    Reschedule
                  </button>
                  <button
                    onClick={() => deleteAppointment(appointment._id)}
                    className="btn"
                    disabled={appointment.status !== "scheduled" || deleting === appointment._id}
                    style={{
                      flex: 1,
                      opacity: appointment.status !== "scheduled" ? 0.5 : 1,
                      color: "var(--danger)",
                      borderColor: "rgba(186, 94, 94, 0.25)",
                    }}
                  >
                    {deleting === appointment._id ? "Cancelling..." : "Cancel Booking"}
                  </button>
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

function SummaryTile({ label, value }) {
  return (
    <div
      style={{
        border: "1px solid rgba(255,255,255,0.16)",
        borderRadius: "16px",
        padding: "16px",
        background: "rgba(255,255,255,0.12)",
        display: "grid",
        gap: "6px",
      }}
    >
      <div style={{ fontSize: "12px", fontWeight: 700, letterSpacing: "0.06em", textTransform: "uppercase", color: "rgba(255,255,255,0.74)" }}>
        {label}
      </div>
      <div style={{ fontSize: "20px", fontWeight: 700, color: "#fff" }}>{value}</div>
    </div>
  );
}
